const Q_GEOGRAPHY_2020_MODEL_II=[{"id": "objective>Geography>2020 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A population with low birth and death rates presents? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an inverted population pyramid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an equal male-female population structure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a broad - based population pyramid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a young dependent population structure</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Low birth rates shows that young age groups and low in the population,while low  <br/> death rate shows large population of old age group ,causing the pyramid to be inverted ,since  <br/> the bottom represent young age group while the top represent old age group. <br/> </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the regions has the least population of density?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Eurasian Tundra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North-west Europe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North-east U.S.A.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Nile Valley</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tundra climate is a transitional climate between the Subarctic and Ice cap climates. It is a region of rolling to nearly level terrain almost entirely devoid of trees. Polar climates like the tundra are characterized by very cold temperatures and generally dry conditions.  <br/> </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors least explains the fast growing population in Africa? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">control of diseases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decline in death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the education of women</div>", "<div style=\"font-family:Cambria;font-size:17px;\">improvement in transportation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Education of women only increases literacy rate and has no effect on population.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of people living in a unit area of land is termed .\t <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Birth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Death rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dependency ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population density</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population Density is a measurement of population per unit area, or exceptionally unit volume. OR Population density is a measurement of population per unit area, or exceptionally unit volume; it is a quantity of type number density.  <br/> </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2020 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Obudu plateau of cross river basin is economically noted for ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tea and coffee plantation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cattle ranching and tourism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exploitation of forest resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Generation of hydro electricity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Obudu plateau of cross river basin is economically noted for 'Cattle ranching and tourism'. The Obudu Plateau is a plateau found on the Oshie Ridge of the Sankwala Mountains, in Cross River State, Nigeria. The plateau is known for its cattle ranch which is a major tourist attraction, and for its unique and beautiful natural scenery.</div>", "topic": "REGIONAL GEOGRAPHY : NIGERIA"}, {"id": "objective>Geography>2020 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A common feature of Forcados Bony and Eket in the Niger Felt is that they are ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Very important fishing port</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Export processing zones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Important for natural gas export</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Terminal for oil compai</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Forcados Bony and Eket are major point in which Nigeria natural gas are exported to other part of Nigeria and world. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : NIGERIA"}, {"id": "objective>Geography>2020 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria towns which hold much of their growth in the 20th century to the development of the rail way includes ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Enugu ,Jos,Kaduna,Minna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos,Minna,Nnewi,Gusau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Osogbo,Minna,Owerri,Jos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos,Lokoja,Gusau,Umuahi</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This rail way was developed by the military government in these part of Nigeria.They includes The Linking Line connects Kaduna on the Western Line to Kafanchan on the Eastern Line. <br/> Ifaw-Ilaro (Western Line), 20 kilometers (12 mi) <br/> Minna-Baro (Western Line), 155 kilometers (96 mi) <br/> Zaria-Kaura Namoda (Western Line), 245 kilometers (152 mi). <br/> Kuru-Jos (Eastern Line), 55 kilometers (34 mi) <br/> Baro-Kano Railway Station (Northern Line), 200 kilometer (120 mi). <br/> </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2020 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most capital-intensive sector of the Nigerian economy today is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trading</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital-intensive sector need a high volume of production to provide an adequate return on investment  <br/>  <br/> Transportation is a very large sector. It covers the different modes of transportation such as air, water, road and rail. The cost of maintaining the routes of these modes of transportation is expensive. Also the facilities such as seaport and airport is costly to maintain, same with the spare parts. <br/> The cost of also building an airplane or ship is really expensive. <br/>  <br/> Other capital intensive companies includes the Energy companies, Automobile manufacturing companies etc</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The name of the volcanic rock which often forms the root of fold mountains is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Batholith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dyke</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lopolith</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A batholith is a large mass of intrusive igneous rock, larger than 100 square kilometres in area, that forms from cooled magma deep in the Earth's crust. Batholiths are almost always made mostly of felsic or intermediate rock types, such as granite, quartz monzonite, or diorite</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are examples of metamorphic rocks  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Basalt and gabbro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gneiss and Quartzite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Granite and gabbro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gneiss and basalt</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gneiss is a common and widely distributed type of rock formed by high-grade regional metamorphic processes from pre-existing formations that were originally either igneous or sedimentary rocks. Quartzite is a non-foliated metamorphic rock that forms by the metamorphism of pure quartz Sandstone. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The section of the external structure of the earth that support life is the ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lithosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Barysphere</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biosphere can be defined as the regions of the surface and atmosphere of the earth or another planet occupied by living organisms.</div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2020 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The scale of the map in statement form is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 centimetres on the map represents 1 kilometre on the ground</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 centimetres on the map represent 1 kilometre on the ground</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 centimetres on the map represent 1 kilometre on the ground</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 centimetres on the map represent 1 kilometre on the ground</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the scale on the map,the bar lines below the graph shows  <br/> 1centimetre each and a km is added at the end of the scale which shows that it is in kilometers . <br/> Scale is defined as the ratio of the distance on a map to the corresponding distance on the surface the map represents. <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>2020 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/>Using the image in above  <br/> Farming is common in <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">North Western part of the map</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North Eastern part of the map</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Western part of the map</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Eastern part of the map</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is true due to the presence of scattered cultivation on the map.Cultivation is the act of caring for or raising plants.  <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2020 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Humid climate the process by which dissolved minerals in a horizon of the soil are transported downwards is known as ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Leaching </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxidation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transpiration </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Leaching is the draining of Nutrient away from the soil due to rain or irrigation. <br/> Calcification is the process of change into a stony or calcareous substance by the deposition of lime salt. <br/> Oxidation is the reaction of elements with oxygen. <br/> Transpiration is the process of giving off water vapour through the skin or mucous membranes. <br/> Percolation is the seepage or filtration of a liquid through a porous substance. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2020 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All of theses are element of weather and climate except  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Altitude</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rainfall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sunshine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">:Altitude is the height measured from sea level up to any given point.Altitude is a factor that affect climate. <br/> The most significant of these elements are temperature, atmospheric pressure, wind, solar irradiance, humidity, precipitation, and topography. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2020 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these group of areas is limestone actively quarried for the manufacturing of cement in Nigeria <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nkalgu,Jos and Ukpilla</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ewekoro,Etinam and Nkalagu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enugu,Nkalagu and Ewekoro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ewekoro,Ukpilla and Nkalagu</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Limestone deposit in Nigeria is majorly deposited in Cross River and Ebonyi state(Nkalagu)but can still be found in commercial deposit in Abia, Akwa Ibom, Anambra,Bayelsa, Benue, Borno, Edo(Ukpilla), Enugu, Imo, Ogun(Ewekoro) Ondo and Sokoto, making Nigeria the most richly deposited West African country when it comes to Limestone. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2020 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The geological structure of Africa is largely composed of ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sedimentary rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Volcanic rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Granitic rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallin rocks </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Granitic rocks are mostly found is Africa countries ,Nigeria for example  has large deposits. <br/> Nigeria is richly endowed with granite stone and other related solid minerals like marble, dolomite and basalt. It is found in Enugu, Ebonyi, Kogi, Plateau, Ogun, Oyo, Osun, Nasarawa and Ekiti States. Hence, granite is among the most available and affordable building materials. <br/>  <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest obstacle to regional economic cooperation in ECOWAS are ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transportation,different currencies and colonial heritage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population distribution, Ethnicity and illitracy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Political instability ,smuggling and high tarrifs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Regional inequality,low productivity and poor communication</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transportation is affected by borders , difficult currencies and colonial heritage is still largely found in francophone West African countries  <br/> </div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2020 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vegetation beds associated with valuable hard woods is the ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sahel savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Corniferous forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean forest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest is characterized by high trees and medium and low plants with abundant rainfall. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2020 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Most warm ocean current flow is? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">In tropical seas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Towards the high latitudes <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Towards the equator</div>", "<div style=\"font-family:Cambria;font-size:17px;\">In high latitudes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Warm ocean currents originate in the tropics and move towards the poles or high latitudes. This is because the purpose of these currents is to distribute heat from the equator to the poles, thereby helping to regulate global climate.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2020 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The size of the individual grains of soil is refered to as the ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Profile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Porosity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Texture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Colloid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Texture is the feel ,sizes or shape of a surface or substance; the smoothness, softness.Soil profile The soil profile is defined as a vertical section of the soil that is exposed by a soil pit.A soil pit is a hole that is dug from the surface of the soil to the underlying bedrock. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2020 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The largest man made lake in Africa is ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Volta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tana</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Malawi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kainji</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lake Volta, the largest artificial reservoir in the world based on surface area, is contained behind the Akosombo Dam which generates a substantial amount of Ghana's electricity. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2020 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a method by which Rivers transport their eroded materials? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Suspension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Traction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Attrition </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Solution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Attrition is not a method by which rivers transport their eroded materials. Rather, it is a process of erosion where the river's load is worn down as particles collide with each other, becoming smaller and rounder. The other options, Suspension, Traction, and Solution, are indeed methods of river transportation. Suspension involves fine particles like silt and clay being carried along by the river. Traction is where larger materials like pebbles and boulders roll along the river bed. Solution is the process where certain types of material are dissolved in the water and carried along.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2020 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A community of plants and animals living in harmony within the same physical environment refers to as? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Environmental interaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Terrestial bio-cycle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ecosystem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biosphere</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecosystem is the interconnectedness of organisms (plants, animals, microbes) with each other and their environment. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2020 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following environmental resources is non-renewable ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Minerals are large deposits found inside the ground and once they are used up they can't be replaced ,unlike Rain and water  through water cycle it is renewable, and Photosynthesis releases oxygen to the atmosphere .</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2020 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A disaster caused by nature of man which poses a serious danger to lives and properties of the people is called environmental ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Intervention</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hazard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Change </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An environmental hazard is a substance, a state or an event which has the potential to threaten the surrounding natural environment / or adversely affect people's health like natural disasters such as storms and earthquakes <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2020 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a prove to show that the Earth is spherical in shape? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sunrise and sunset</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aerial photograph </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lunar eclipse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Twilight and Dawn</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Twilight and dawn are caused because of 'scattering of sunlight' off the atmosphere. Twilight and dawn are periods when little light is visible in the sky. Twilight is time period between sunrise and dawn or between sunset and dusk. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2020 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The time in town X on longitude 15°E is 4.00pm .What will be the time in town Y on longitude 15°W? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.00am</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00pm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.00pm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.00am</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Longitude 15°E :Town X <br/> Longitude 15°W ;Town Y <br/> 4.00pm? <br/> 1°=4minutes <br/> 15°=1hrs <br/> 15°E+ 15°W=30° <br/> If 15°=1hr <br/> 30°=? <br/> 30° X 1hr ÷15°= 2hrs  <br/> Since we are looking for the time in town Y,we subtract 4.00pm-2hrs =2.00pm <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : THE EARTH AS A PLANET"}, {"id": "objective>Geography>2020 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sills, dykes and batholiths are examples of <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">intrusive volcanic landforms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extrusive volcanic landforms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">landforms from earthquakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depositional landforms</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Batholiths  are the intrusive igneous rocks masses formed due to the cooling and the solidification of Magma inside the earth. These intrusive igneous rocks appear on the surface after the erosional process erode the materials lying above these rocks.Sills are the intrusive igneous rocks which are formed by the solidified and near horizontal lava layers inside the earth.  <br/> When the Magma moves upwards through the cracks and fissures, and solidifies almost perpendicularly to the earth s surface, developing a wall like structure, they are known as dykes.  <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2020 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a measure of environment control? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Preservation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stabilisation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Degradation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Afforestation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Degradation is the process of the lowering of a fluvial surface, i.e. a riverbed, basin, watershed, or floodplain, by means of erosion. An example includes rivers becoming deeper by sediment being eroded away from the bottom surface. <br/> </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2020 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The foremost producers of petroleum in the middle east are ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Saudi arabia,Kuwait ,Libya and Iran</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saudi Arabia,Iran,Iraq,Kuwait</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saudi Arabia, Venezuela ,Iran and Oman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Saudi Arabia ,Iraq ,Libya and Venezuela</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Libya is an Africa country <br/> Venezuela is in South America <br/> Option B contains purely countries in middle east and they are producers of petroleum. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The merging together of a number of urban settlement will produce a? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Conurbation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nucleated Settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Suburb</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A conurbation is a region comprising a number of metropolises, cities, large towns, and other urban areas that, through population growth and physical expansion, have merged to form one continuous urban or industrially developed area. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2020 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The likely occupation of the people in the area is <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market gardening</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of scattered cultivation and palms with settlements combines together to show that the people leaving in this area are involved in farming. <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2020 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In chain surveying, the basic principle is to measure? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">angles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heights</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depths</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distances</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chain surveying is the type of surveying in which only linear measurements are made in the field. The main principle of chain surveying or chain triangulation is to provide a framework consist of number of well-conditioned triangles or nearly equilateral triangles. It is used to find the area of the field. <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2020 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following methods of representing statistical data would be the most suitable for showing annual production of rice on a month-to-month basis? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Line graph</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pie chart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bar chart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Flow chart</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A bar chart or bar graph is a chart or graph that presents categorical data with rectangular bars with heights or lengths proportional to the values that they represent. The bars can be plotted vertically or horizontally. A bar graph shows comparisons among discrete categories. <br/> </div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2020 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main petroleum producing countries of Africa are ? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria, Togo and South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria,Ivory coast and Zaire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria ,Algeria and Tunisia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria, Algeria and Libya</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria produced more than 1.9 million barrels of oil per day in 2014 to rank as the 11th-largest oil producer in the world and First in Africa .Algeria produced approximately 1.3 million barrels of oil per day in 2019 to maintain its position among the top tier of African oil producers.Libya produced almost 1.2 million barrels of oil per day in 2019. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2020 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria produces locally the major raw materials for the manufacture of all but one of these home made goods? <br/>  <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bar soap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Refined petroleum products</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium production such as pretroluem products and pitch are imported for the manufacturing of aluminum into Nigeria . <br/> </div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2020 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the commodity associated with OPEC? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron and steel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineral oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetable oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sugar</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">OPEC stands for Organization of Petroleum exporting countries.It is an organization for countries that export petroleum to other parts of the world ,countries.Nigeria,Algeria , Venezuela,Libya etc. <br/> </div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2020 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the following countries produces more rice than the others.which is it? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">China</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ivory Coast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thailand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fully half of Thailand's cultivated land is devoted to rice. The Thai Ministry of Agriculture projects paddy production for both the main and second crops to hit 27-28 million tonnes in the 2019 <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2020 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following towns in Nigeria is noted for the production of glass beads as a traditional craft? <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bida</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Keffi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sokoto</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oshogbo</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The town of Bida, Niger state, north-central Nigeria is not new to ancient crafts. Bida is noted for unique arts dating back hundreds of years. Bida villagers engaged in steel making, black smiting and glass beads making long before white men set foot on the shores of West-Africa. <br/> </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}];
